var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"딸아이가 입원을 했는데, 아빠가 얼굴 한 번 안 비추는 게 말이 돼?","JPN":"自分の娘が入院したというのに、一度も顔を出さないなんて、それでも父親なの？","ENG":"Your daughter's hospitalized, and you can't even drop by for a visit?","TWN":"女兒住院，身為父親，你卻一次都沒來看過她，這像話嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>간만에 프로젝트에 진척이 생겨서. 오늘도 당신 혼자 챙겨줘야 할 것 같아.</color>","JPN":"<color=#ffd34c>やっとプロジェクトが動き始めたんだ。そうあることじゃないし、今日も君に世話は頼んだぞ。</color>","ENG":"<color=#ffd34c>We've made a breakthrough in our project. So you'll have to take care of her alone for today.</color>","TWN":"<color=#ffd34c>項目難得有進展。今天也得要你照顧下她。</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"누군 시간 없어? 나도 내 연구 다 제쳐두고 온 거야.","JPN":"私だって自分の研究はそっちのけでここに来ているのよ？","ENG":"And you think I've got the time? I had to shelf all my research to be here.","TWN":"誰不忙？我也是放下了手頭的研究來照顧她啊。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>정말 미안해, 다이앤.</color>","JPN":"<color=#ffd34c>本当にすまない。ダイアン。</color>","ENG":"<color=#ffd34c>I'm really sorry, Diana.</color>","TWN":"<color=#ffd34c>我很抱歉，黛安娜。</color>"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>아이 생일 전까진 휴가 받아서 들를게.</color>","JPN":"<color=#ffd34c>あの子の誕生日までには休みを取って行けるようにするよ。</color>","ENG":"<color=#ffd34c>I'll make sure to take some time off from work before her birthday.</color>","TWN":"<color=#ffd34c>我會在孩子生日前，請假去看她的。</color>"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래… 마음대로 해.","JPN":"はあ……好きにすれば。","ENG":"Sure... whatever.","TWN":"好……隨便你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"이만 끊자.","JPN":"もういいわ、切るわね。","ENG":"Bye.","TWN":"我掛了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"…병실 밥은 입맛에 맞니?","JPN":"……病院の食事はどう？","ENG":"...How's the food? Do you like it?","TWN":"……醫院的食物怎麼樣？還吃得慣嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"잘 모르겠어.","JPN":"よくわからない。","ENG":"I’m not sure.","TWN":"我不知道……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래도 잘 먹어야 건강해지지.","JPN":"でも食べないと元気にならないわよ。","ENG":"You have to eat to get better soon.","TWN":"那也得吃，這樣身體才能好得快。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"...아빠는 언제 와요?","JPN":"……お父さんはいつ来るの？","ENG":"...When is dad coming?","TWN":"……爸爸、爸爸什麼時候會來？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"네 생일날엔 꼭 오겠다고 하시네.","JPN":"誕生日には来るって。","ENG":"He promised to be here on your birthday.","TWN":"爸爸說等到你生日那天，他一定會來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"정말?","JPN":"本当？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래. 생일 선물로 뭘 받고 싶은지 생각해두는 건 어때?","JPN":"ええ。誕生日プレゼント、何が欲しいか考えておいたら？","ENG":"Of course. So why don't you think about what you want for your birthday present?","TWN":"當然了。所以現在不如好好想想，生日那天想要什麼禮物？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"음...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마가 나처럼 아프지 않았으면 좋겠어요.","JPN":"お母さんが私みたいに体調を崩さないでほしいかな。","ENG":"I want you to be healthy, Mommy. Unlike me.","TWN":"我想讓媽媽快點好起來，不要像我一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그게… 무슨 소리니?","JPN":"うん……？　 どういうこと？","ENG":"What... do you mean by that?","TWN":"……你在說什麼呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"5년 전에 아빠가 날 데리고 사라졌잖아요.","JPN":"5年前。お父さんが私を連れていなくなって。","ENG":"Remember how Daddy took me and left you five years ago?","TWN":"五年前，爸爸不是帶著我一起失蹤了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"그래서 엄마도 5년 동안 아빠만 찾아다니다 나랑 똑같은 병에 걸렸고요.","JPN":"お母さんは5年間も、お父さんのことを探し回って、私と同じ病気になっちゃった。","ENG":"And you got sick with the same thing I had while looking for him for five years?","TWN":"結果媽媽找了我們五年，最後也得了和我一樣的病。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"이건 꿈이구나.","JPN":"そうか、これは夢。","ENG":"This is a dream.","TWN":"原來，是夢啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"하긴, 생일이 되기 전에 침식증후군이 네 목소리를 빼앗아갔으니까.","JPN":"ああ……誕生日を迎える前に、あなたは侵食症候群に声を奪われたから。","ENG":"I mean, of course, it is. The Corruption Syndrome took your voice before your birthday came.","TWN":"咳，當然了。侵蝕症候群在你生日之前就奪走了你的聲音。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래서 우린 헤어지는 날까지 제대로 대화도 한 번 못 나눴지.","JPN":"だからあなたとは、お別れの瞬間まで一言も言葉を交わすことができなかった。","ENG":"We couldn't even have a proper conversation until the day we had to say goodbye.","TWN":"所以，直到分離的那天，我們都沒能好好說上一句話。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마…","JPN":"お母さん……","ENG":"Mommy...","TWN":"媽媽……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"네 아버지가 널 데려갈 거란 것도, 난 네가 사라질 때까지 몰랐어.","JPN":"あなたの父親が、あなたを連れ去ることも、その時になるまで知らなかった。","ENG":"I didn't even think your dad would take you away until you disappeared.","TWN":"我從未想過爸爸會把你一起帶走。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"알고 있었다면 내가 막았을 텐데.","JPN":"もし気づいていたら、止めることもできたのに。","ENG":"I would've stopped him if I had known.","TWN":"如果早點知道的話，一定會阻止他的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"꿈에서 깨어나고 싶어요?","JPN":"お母さん……夢から目覚めたいの？","ENG":"Do you want to wake up from this dream?","TWN":"媽媽，你現在要醒了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"아니. 널 이렇게나마 계속 보고 싶어.","JPN":"ううん。こうしてあなたの顔が見られるだけで幸せだもの。","ENG":"No. I still want to see you. Even if it's like this.","TWN":"不。我想繼續這樣看著你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"하지만 이젠… 꿈속의 네 얼굴마저 흐릿해져.","JPN":"でももう……夢の中のあなたの顔までぼんやりしてしまっている。","ENG":"But... My memory of your face is getting blurry, even in my dreams.","TWN":"但現在……就算在夢中，記憶中的面容也變得模糊不清。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"언젠가는 너에 대한 기억이 완전히 사라져버리진 않을까… 그게 두려워.","JPN":"このままではいつか、あなたのことを完全に忘れてしまうんじゃないかって……怖いわ。","ENG":"I'm afraid... that I might one day completely forget about you.","TWN":"我很擔心，有一天，我會不會徹底把你忘記……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마도 아프잖아요. 나처럼.","JPN":"仕方ないよ。お母さんも私と同じ病気になったんだから。","ENG":"Mommy, you're also sick. Like me.","TWN":"媽媽也很痛苦吧。就像我一樣。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"걱정 마. 버틸 거야.","JPN":"大丈夫。お母さんは耐えてみせるから。","ENG":"Don't worry. I'll get through this.","TWN":"別擔心。我會堅持下去的。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"적어도, 널 찾을 때까진.","JPN":"あなたを見つけ出すまでは、絶対に。","ENG":"At least, until I find you.","TWN":"至少，在我找到你之前。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"북방합의체로부터 관리국 조항에 위배되는 연구자료가 적발되었습니다.","JPN":"北方合意体内部から管理局条項に違反する研究資料が摘発されました。","ENG":"Research data that violates the Administration's policy has been discovered in the Northern Union.","TWN":"據悉，相關人員在北方和議會發現了違反管理局條例的研究資料。"},"stage":{"bg":"RELIC_OPERATION_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"한 익명의 제보로 인해 침식체를 무기화하려던 정황이 드러난 것입니다.","JPN":"匿名の通報により、侵食体を兵器化しようとしていた状況が明るみに出たのです。","ENG":"An anonymous tip has revealed that there had been attempts to weaponize C.O.s.","TWN":"有匿名舉報稱，有人試圖將侵蝕體武器化的事實。"},"stage":{"bg":"RELIC_OPERATION_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"북방합의체 외교부는 이 프로젝트가 국가산업과는 일체 연관이 없으며, 재외국민들이 관리국 감시를 피하기 위해 국가 명의를 도용했을 뿐이라 일축했습니다.","JPN":"北方合意体の外交省は、今回のプロジェクトについて国家事業とは一切無関係であり、管理局の監視網を潜り抜けるために、在外国民による国名の盗用であると立場を明らかにしました。","ENG":"The Foreign Affairs Ministry of the Northern Union rebutted, claiming that this project had nothing to do with national affairs and was an attempt by foreign nationals to use their country's name to avoid the Administration's surveillance.","TWN":"北方和議會外交部回應了此次舉報，聲稱該項目與本國無關，是海外人士為躲避管理局的監視，冒用了其名義。"},"stage":{"bg":"RELIC_OPERATION_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아울러 북방합의체는 관리국의 조사에 적극적으로 협조하겠단 의사를 덧붙이며, 프로젝트에 가담했던 재외국민 연구진들의 명단을 제공하고 공개수배하기로 했습니다.","JPN":"なお、本件においては管理局の調査に全面的に協力するとの意志を表明し、プロジェクトに加担していたとみられる在外国民の研究者らの名簿を公開し、指名手配を行うとのことです。","ENG":"Furthermore, the Northern Union has expressed its willingness to actively cooperate with the Administration's investigation, agreeing to provide a list of overseas nationals who were involved in the project and to issue warrants for their arrest.","TWN":"此外，北方和議會表示願意積極配合管理局的調查，並同意提供參與該項目的海外研究人員名單，公開對其進行懸賞。"},"stage":{"bg":"RELIC_OPERATION_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>금일 챔버 오스왈드 구역 침식파 농도는 양호 수준입니다.</color>","JPN":"<color=#ffd34c>本日のチェンバー、オズワルド区域の侵食派濃度は良好です。</color>","ENG":"<color=#ffd34c>Today's Corruption rays in the Chamber's Oswald zone are at acceptable levels.</color>","TWN":"<color=#ffd34c>今日強巴，奧斯維德區域的侵蝕波濃度水準良好。</color>"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이터니움 필터 없는 건강한 외출 되세요.</color>","JPN":"<color=#ffd34c>エタニウムフィルターなしで健やかにお出かけください。</color>","ENG":"<color=#ffd34c>Please enjoy your day without the need for an Eternium filter.</color>","TWN":"<color=#ffd34c>無需永恆之金篩檢程式即可正常外出。</color>"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"으음…","JPN":"うむ……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아.","JPN":"はあ。","ENG":"*Sigh*","TWN":"呼——"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"관리국은 그대들을 속이고서 진실을 숨기고 있소!","JPN":"管理局はあなたたちの目を眩ませ、真実を隠している！","ENG":"The Administration is lying to you and hiding the truth!","TWN":"管理局在隱瞞真相，欺騙大眾！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L22_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"관리국의 거짓에 휘둘리지 마시오! 마젤란을 믿는 길이 곧 구원이오!","JPN":"管理局の嘘に惑わされてはダメだ！　マジェランの言葉こそが救いなり！","ENG":"Don't fall for their petty lies! Have faith in Magellan and be granted salvation!","TWN":"不要被管理局的謊言所迷惑！唯有相信麥哲倫才是救贖！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"침식증후군은 질병이 아니라 낙원으로 가는 축복이라오!","JPN":"侵食症候群は疾患なんかではない、楽園への祝福である！","ENG":"The Corruption Syndrome is not a disease, but a blessing that will lead us to paradise!","TWN":"侵蝕症候群不是一種疾病，而是通往樂園的祝福！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CIVILIANS_FLOOR_NULL_NULL","text":{"KOREA":"그 사이비 놈들 망한 지가 언젠데, 아직도 저런 소릴하는 인간이 있다니.","JPN":"あのカルト宗教団体、とっくに解散したと思ってたけど、まだ残ってる奴がいたんだな。","ENG":"That cult went under a while ago. So why are there still psychos like that roaming the streets?","TWN":"那些邪教組織已經垮台多久了，還有人說這樣的話。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIVILIANS_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CIVILIANS_FLOOR_NULL_NULL","text":{"KOREA":"쯧쯧, 불쌍한 인간.","JPN":"やれやれ、かわいそうに。","ENG":"Tsk, tsk. Poor person.","TWN":"嘖嘖，可憐的人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CIVILIANS_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CIVILIANS_FLOOR_NULL_NULL","text":{"KOREA":"뭐가 구원이고 새로운 인류야! 침식증후군에 걸린 사람이 얼마나 고통스럽게 죽는데!","JPN":"救いだの新人類だの適当なこと言ってんじゃねえ！　侵食症候群にかかった人がどんだけ苦しんで死んでいくのかわかって言ってんのか！","ENG":"Cut the crap about salvation and new humanity! Do you know how painful people with Corruption Syndrome die?!","TWN":"什麼拯救、什麼新人類！得了侵蝕症候群的人死得多痛苦啊！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIVILIANS_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"세계가 변화를 원하고 있으나, 무지한 인간은 변화를 두려워한다오.","JPN":"世界が変化しようとしていることも知らず、無知な人間たちはその変化に怯える。","ENG":"The world desires change, but ignorant humans fear it.","TWN":"世界需要改變，但無知的人卻害怕改變。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIVILIANS_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"저항하지 말고 침식을 받아들이시오! 당신도…!","JPN":"抗うのはやめ、侵食を受け入れるのです！　そこのあなたも……！","ENG":"Do not resist and accept the Corruption! You too can be saved...!","TWN":"不要反抗，擁抱侵蝕！你……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"그리고 거기 당신도…!","JPN":"そして、はい、そこのあなたもです……！","ENG":"And you...!","TWN":"還有你……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"손 치워, 아저씨.","JPN":"その手をどかしな、おじさん。","ENG":"Get your hand off me, creep.","TWN":"把手拿開，大叔。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"죽을 병에 걸렸으면 남은 시간 악착같이 살기나 해. 헛된 희망으로 남의 발목 붙잡지 말고.","JPN":"病気でもうすぐ死ぬんなら、残りの人生を精一杯生きたらいい。ありもしない夢物語で他人の後ろ髪を引こうとしないでさ。","ENG":"If you got something chronic, why don't you live like you mean it? Don't drag everyone else down with your flimsy hopes.","TWN":"你要是真得了侵蝕病，那就頑強地活完下半輩子。不要抱著不切實際的希望，拉別人下水。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"축복을 병으로 취급하다니…! 이런 불경한 자를 보았나!","JPN":"祝福が病だと……！　この不届き者が！","ENG":"You dare treat a blessing as an illness...? You blasphemous wench!","TWN":"你竟將祝福視作疾病……！怎會有你這樣的褻瀆之人！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MISSIONARY_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"당신… TV에서 본 것 같은데?","JPN":"あなた……確かテレビで見たことがある。","ENG":"You... I think I saw you on TV before.","TWN":"……我好像在電視上看到過你？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L43_1","type":"dialog","speaker":"MISSIONARY_FLOOR_NULL_NULL","text":{"KOREA":"5년 전에 이터니움 정제액을 개발했다던 그 박사… 맞지?","JPN":"5年前、エタニウム精製水を開発した博士……あなたなんだろう？","ENG":"You're that doctor who invented the purified Eternium liquid five years ago... right?","TWN":"你是五年前開發出永恆之金淨化液的博士……對吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"바깥이 소란스럽더군요.","JPN":"外が騒がしかったですね。","ENG":"It's rather noisy outside.","TWN":"外面可真吵。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"유토피아건 세기말이건, 종말론자는 항상 있나 봐요. 다 끝나면 그때부턴 아무 의미도 없는 건데.","JPN":"ユートピアにも世紀末にも、終末論を唱える者はどこにでもいますね。終わってしまえば、その先は何もないというのに。","ENG":"Whether we're in a utopia or in moral decay, we can't seem to escape doomsayers. Even though nothing will matter when it's all over.","TWN":"無論太平盛世還是世界末日，總有這樣危言聳聽的預言者。照我說，要是真的什麼都完了，到時候一切還有什麼意義？你說對吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…난 이런 밝은 곳은 질색이야.","JPN":"……私、こういう明るい場所は苦手。","ENG":"...I hate bright places like this.","TWN":"……我討厭這樣明亮的地方。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"에이, 가끔은 이런 분위기에서 커피를 마시는 것도 좋잖아요. 멀쩡한 사회의 일원 같고요.","JPN":"たまにはこういうところでコーヒーを飲むのもいいじゃないですか。普通の社会人みたいで。","ENG":"Hey now, it's nice to enjoy some coffee in a place like this sometimes. It makes you feel like a normal member of society.","TWN":"哎呀，不過有時候在這樣的氛圍下喝杯咖啡也不錯。看起來才像是正常社會的一員。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"됐고. 본론.","JPN":"そう。それで本題は。","ENG":"Enough. Cut to the chase.","TWN":"行了，說正事吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"리프팅 의뢰가 들어왔어요. 대균열에서 실종된 시신을 수습해달라고 하더군요.","JPN":"リフティングの依頼です。大亀裂で行方不明になった遺体を回収して欲しいとのことです。","ENG":"A lifting request came in. They're asking us to recover missing bodies from the Grand Dimension Crevice.","TWN":"收到一個尋人的委託，要我們找回在大峽谷裡失蹤的屍體。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"몇 층이지?","JPN":"何階になるんだ？","ENG":"Which floor?","TWN":"第幾層？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"2층, 샹그릴라 동토입니다. 좌표는…","JPN":"2階、シャングリラ凍土です。座標は……","ENG":"2nd floor. Gelid Lands of Shangri-La. The coordinates are–","TWN":"地下二層，香格里拉凍土。座標是……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"브리핑 자료 넘겨. 바로 출발한다고 전해.","JPN":"詳細情報をちょうだい。すぐ向かうと伝えて。","ENG":"Send me the briefing. Tell them I'll depart right away.","TWN":"給我簡報資料。告訴他們，我立刻出發。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"괜찮은 거예요? 지난 탐사에서 복귀하신 지 아직 며칠 안 됐잖아요.","JPN":"いいんですか？　まだ復帰してからそんなに経っていないのに。","ENG":"Will you be all right? It's only been a few days since you came back from your last exploration.","TWN":"你確定沒問題？距離你上次出去回來才過了沒幾天。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"대균열을 너무 자주 들락거리면 몸이 망가진다고요.","JPN":"あまり頻繁に大亀裂に出入りすると身体を壊しちゃいますよ。","ENG":"You'll hurt yourself if you go in and out of the Grand Dimension Crevice so often.","TWN":"太過頻繁地進出大峽谷的話，身體會崩潰的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식환자는 어차피 죽어.","JPN":"侵食患者はどのみち死ぬ運命だ。","ENG":"Corruption Syndrome patients all die anyway.","TWN":"侵蝕患者無論如何都會死。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"사지 멀쩡할 때 많이 벌어둬야지.","JPN":"手足がまだ動くうちに、できるだけ稼がないと。","ENG":"Gotta make a living while I still can.","TWN":"趁還活著的時候，就該多賺點錢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"알겠습니다. 부디 조심해서 다녀오세요.","JPN":"わかりました。どうか気をつけて行ってきてください。","ENG":"All right. Stay safe out there.","TWN":"我知道了。請務必要小心。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};